const sdContacts = $('GET SuiteDash Contacts').first().json.data || [];
const atRecords = $('GET AiTable Clients').first().json.data?.records || [];

// Build lookup maps
const sdMap = new Map();
for (const c of sdContacts) {
  sdMap.set(c.email?.toLowerCase(), c);
}

const atMap = new Map();
for (const r of atRecords) {
  atMap.set(r.fields.email?.toLowerCase(), r);
}

const toCreate = []; // In AiTable but not SuiteDash (shouldn't happen, but log it)
const toUpdate = []; // In both, but fields differ
const orphaned = []; // In AiTable but not in SuiteDash

// Check AiTable records against SuiteDash
for (const [email, atRecord] of atMap) {
  if (!sdMap.has(email)) {
    orphaned.push({email, aitable_id: atRecord.recordId, reason: 'in_aitable_not_suitedash'});
  } else {
    const sd = sdMap.get(email);
    const at = atRecord.fields;
    // Check for field drift
    const drifts = [];
    if (sd.custom_membership_tier && at.membership_tier && sd.custom_membership_tier !== at.membership_tier) {
      drifts.push({field: 'membership_tier', suitedash: sd.custom_membership_tier, aitable: at.membership_tier});
    }
    if (sd.custom_lifecycle_stage && at.lifecycle_stage && sd.custom_lifecycle_stage !== at.lifecycle_stage) {
      drifts.push({field: 'lifecycle_stage', suitedash: sd.custom_lifecycle_stage, aitable: at.lifecycle_stage});
    }
    if (drifts.length > 0) {
      toUpdate.push({email, suitedash_id: sd.id, aitable_id: atRecord.recordId, drifts});
    }
  }
}

// Check SuiteDash contacts not in AiTable
for (const [email, sdContact] of sdMap) {
  if (!atMap.has(email)) {
    toCreate.push({
      email,
      suitedash_id: sdContact.id,
      name: `${sdContact.first_name || ''} ${sdContact.last_name || ''}`.trim(),
      reason: 'in_suitedash_not_aitable'
    });
  }
}

const summary = {
  suitedash_count: sdContacts.length,
  aitable_count: atRecords.length,
  to_create_in_aitable: toCreate.length,
  to_update: toUpdate.length,
  orphaned: orphaned.length,
  sync_time: new Date().toISOString()
};

return [{
  json: {
    summary,
    to_create: toCreate,
    to_update: toUpdate,
    orphaned,
    has_issues: toCreate.length > 0 || toUpdate.length > 0 || orphaned.length > 0
  }
}];

const data = $input.first().json;
const toCreate = data.to_create || [];
const results = [];

for (const item of toCreate) {
  results.push({
    json: {
      fields: {
        client_id: item.suitedash_id,
        suitedash_id: item.suitedash_id,
        email: item.email,
        name: item.name,
        lifecycle_stage: 'active',
        engagement_score: 0,
        signup_date: new Date().toISOString()
      }
    }
  });
}

return results.length > 0 ? results : [{json: {skip: true}}];

